CREATE OR REPLACE FUNCTION sync_module_item_data_to_item_data() RETURNS TRIGGER AS $$ BEGIN IF pg_trigger_depth() > 1 THEN RETURN COALESCE(NEW, OLD); END IF;
IF (TG_OP = 'INSERT') THEN INSERT INTO item_data ( item_data_id, item_id, event_crf_id, value, ordinal, status_id, deleted, date_created, date_updated, owner_id, update_id ) VALUES ( NEW.item_data_id, NEW.item_id, NEW.event_crf_id, NEW.value, NEW.ordinal, NEW.status_id, NEW.deleted, NEW.date_created, NEW.date_updated, NEW.owner_id, NEW.update_id ) ON CONFLICT (item_data_id) DO UPDATE SET item_id = EXCLUDED.item_id, event_crf_id = EXCLUDED.event_crf_id, value = EXCLUDED.value, ordinal = EXCLUDED.ordinal, status_id = EXCLUDED.status_id, deleted = EXCLUDED.deleted, date_created = EXCLUDED.date_created, date_updated = EXCLUDED.date_updated, owner_id = EXCLUDED.owner_id, update_id = EXCLUDED.update_id; RETURN NEW; ELSIF (TG_OP = 'UPDATE') THEN UPDATE item_data SET item_id = NEW.item_id, event_crf_id = NEW.event_crf_id, value = NEW.value, ordinal = NEW.ordinal, status_id = NEW.status_id, deleted = NEW.deleted, date_created = NEW.date_created, date_updated = NEW.date_updated, owner_id = NEW.owner_id, update_id = NEW.update_id WHERE item_data_id = OLD.item_data_id; RETURN NEW; ELSIF (TG_OP = 'DELETE') THEN DELETE FROM item_data WHERE item_data_id = OLD.item_data_id; RETURN OLD; END IF; END; $$ LANGUAGE plpgsql;
CREATE OR REPLACE FUNCTION sync_item_data_to_module_item_data() RETURNS TRIGGER AS $$ BEGIN IF pg_trigger_depth() > 1 THEN RETURN COALESCE(NEW, OLD); END IF;
IF (TG_OP = 'INSERT') THEN INSERT INTO module_item_data ( item_data_id, item_id, event_crf_id, value, ordinal, status_id, deleted, date_created, date_updated, owner_id, update_id ) VALUES ( NEW.item_data_id, NEW.item_id, NEW.event_crf_id, NEW.value, NEW.ordinal, NEW.status_id, NEW.deleted, NEW.date_created, NEW.date_updated, NEW.owner_id, NEW.update_id ) ON CONFLICT (item_data_id) DO UPDATE SET item_id = EXCLUDED.item_id, event_crf_id = EXCLUDED.event_crf_id, value = EXCLUDED.value, ordinal = EXCLUDED.ordinal, status_id = EXCLUDED.status_id, deleted = EXCLUDED.deleted, date_created = EXCLUDED.date_created, date_updated = EXCLUDED.date_updated, owner_id = EXCLUDED.owner_id, update_id = EXCLUDED.update_id; RETURN NEW; ELSIF (TG_OP = 'UPDATE') THEN UPDATE module_item_data SET item_id = NEW.item_id, event_crf_id = NEW.event_crf_id, value = NEW.value, ordinal = NEW.ordinal, status_id = NEW.status_id, deleted = NEW.deleted, date_created = NEW.date_created, date_updated = NEW.date_updated, owner_id = NEW.owner_id, update_id = NEW.update_id WHERE item_data_id = OLD.item_data_id; RETURN NEW; ELSIF (TG_OP = 'DELETE') THEN DELETE FROM module_item_data WHERE item_data_id = OLD.item_data_id; RETURN OLD; END IF; END; $$ LANGUAGE plpgsql;
DROP TRIGGER IF EXISTS trg_sync_module_item_data ON module_item_data; CREATE TRIGGER trg_sync_module_item_data AFTER INSERT OR UPDATE OR DELETE ON module_item_data FOR EACH ROW EXECUTE FUNCTION sync_module_item_data_to_item_data();
DROP TRIGGER IF EXISTS trg_sync_item_data_to_module ON item_data; CREATE TRIGGER trg_sync_item_data_to_module AFTER INSERT OR UPDATE OR DELETE ON item_data FOR EACH ROW EXECUTE FUNCTION sync_item_data_to_module_item_data();

CREATE OR REPLACE FUNCTION sync_module_item_group_to_item_group()
RETURNS TRIGGER AS $$
BEGIN
    IF pg_trigger_depth() > 1 THEN
        RETURN COALESCE(NEW, OLD);
    END IF;

    IF (TG_OP = 'INSERT') THEN
        INSERT INTO item_group (
            item_group_id, crf_id, name, oc_oid,
            status_id, date_created, date_updated,
            owner_id, update_id
        )
        VALUES (
            NEW.item_group_id, NEW.crf_id, NEW.name, NEW.oc_oid,
            NEW.status_id, NEW.date_created, NEW.date_updated,
            NEW.owner_id, NEW.update_id
        )
        ON CONFLICT (item_group_id) DO UPDATE SET
            crf_id = EXCLUDED.crf_id,
            name = EXCLUDED.name,
            oc_oid = EXCLUDED.oc_oid,
            status_id = EXCLUDED.status_id,
            date_created = EXCLUDED.date_created,
            date_updated = EXCLUDED.date_updated,
            owner_id = EXCLUDED.owner_id,
            update_id = EXCLUDED.update_id;
        RETURN NEW;
    ELSIF (TG_OP = 'UPDATE') THEN
        UPDATE item_group SET
            crf_id = NEW.crf_id,
            name = NEW.name,
            oc_oid = NEW.oc_oid,
            status_id = NEW.status_id,
            date_created = NEW.date_created,
            date_updated = NEW.date_updated,
            owner_id = NEW.owner_id,
            update_id = NEW.update_id
        WHERE item_group_id = OLD.item_group_id;
        RETURN NEW;
    ELSIF (TG_OP = 'DELETE') THEN
        DELETE FROM item_group WHERE item_group_id = OLD.item_group_id;
        RETURN OLD;
    END IF;
END;
$$ LANGUAGE plpgsql;

