DROP TRIGGER IF EXISTS trg_sync_module_item_group ON module_item_group;
CREATE TRIGGER trg_sync_module_item_group
AFTER INSERT OR UPDATE OR DELETE ON module_item_group
FOR EACH ROW EXECUTE FUNCTION sync_module_item_group_to_item_group();

DROP TRIGGER IF EXISTS trg_sync_item_group_to_module ON item_group;
CREATE TRIGGER trg_sync_item_group_to_module
AFTER INSERT OR UPDATE OR DELETE ON item_group
FOR EACH ROW EXECUTE FUNCTION sync_item_group_to_module_item_group();

CREATE OR REPLACE FUNCTION sync_module_response_set_to_response_set()
RETURNS TRIGGER AS $$
BEGIN
    IF pg_trigger_depth() > 1 THEN
        RETURN COALESCE(NEW, OLD);
    END IF;

    IF (TG_OP = 'INSERT') THEN
        INSERT INTO response_set (
            response_set_id, response_type_id, label,
            options_text, options_values, version_id
        )
        VALUES (
            NEW.response_set_id, NEW.response_type_id, NEW.label,
            NEW.options_text, NEW.options_values, NEW.version_id
        )
        ON CONFLICT (response_set_id) DO UPDATE SET
            response_type_id = EXCLUDED.response_type_id,
            label = EXCLUDED.label,
            options_text = EXCLUDED.options_text,
            options_values = EXCLUDED.options_values,
            version_id = EXCLUDED.version_id;
        RETURN NEW;
    ELSIF (TG_OP = 'UPDATE') THEN
        UPDATE response_set SET
            response_type_id = NEW.response_type_id,
            label = NEW.label,
            options_text = NEW.options_text,
            options_values = NEW.options_values,
            version_id = NEW.version_id
        WHERE response_set_id = OLD.response_set_id;
        RETURN NEW;
    ELSIF (TG_OP = 'DELETE') THEN
        DELETE FROM response_set WHERE response_set_id = OLD.response_set_id;
        RETURN OLD;
    END IF;
END;
$$ LANGUAGE plpgsql;

